final:
module pulse_gen(
    input wire clk,
    input wire rst_n,
    input wire signal_in,
    output reg pulse_out
);

reg signal_in_q;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        signal_in_q <= 1'b0;
        pulse_out <= 1'b0;
    end else begin
        signal_in_q <= signal_in;
        pulse_out <= signal_in && !signal_in_q;
    end
end

endmodule
